window.TOPICS = TOPICS;
window.LESSONS = LESSONS;
window.VOCAB_CARDS = VOCAB_CARDS;

// Assign stable _id to every lesson exercise once on load
(function assignExerciseIds() {
  Object.entries(LESSONS).forEach(([topicId, lesson]) => {
    lesson.exercises.forEach((ex, i) => {
      if (!ex._id) ex._id = topicId + '#' + i;
    });
  });
})();

// Reverse: production-style gaptype — type the missing word from a real example
function generateReverseExercises() {
  const out = [];
  VOCAB_CARDS.forEach(card => {
    if (/\s/.test(card.en)) return; // skip multi-word phrases
    const re = new RegExp('\\b' + card.en.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i');
    if (!re.test(card.ex)) return;
    const sentence = card.ex.replace(re, '___');
    out.push({
      _id: 'rev#' + card.en.replace(/\s+/g, '_'),
      _topicId: null,
      type: 'gaptype',
      tag: 'Vocabulary',
      prompt: 'Type the missing word (means: "' + card.def + '").',
      sentence,
      answer: card.en,
    });
  });
  return out;
}

// Production: turn recognition-style exercises into typed-answer drills.
// gap     → gaptype  (fill the blank, typed)
// choice  → type     (only when prompt isn't a pure recognition question
//                     and the answer is short enough to be typeable)
// bank    → type     (always — typing the full sentence)
// explain → gaptype  (the idiom is the typed answer in a short prompt)
// simile  → gaptype  (template with one typed blank)
function toProductionVariant(ex, topicId, idx) {
  if (ex.type === 'gap') {
    return {
      _id: 'prod#' + topicId + '#' + idx,
      _topicId: topicId,
      type: 'gaptype',
      tag: ex.tag,
      prompt: ex.prompt,
      sentence: ex.sentence,
      answer: ex.answer,
    };
  }
  if (ex.type === 'choice') {
    const a = ex.answer || '';
    const tooLong = a.split(/\s+/).length > 3 || a.length > 25;
    if (tooLong) return null;
    const recognitionPatterns = [
      /which (phrase|adjective|verb|word|expression|sentence|is correct|means)/i,
      /what does .+ mean/i,
      /most nearly means/i,
      /refers to/i,
    ];
    if (recognitionPatterns.some(r => r.test(ex.prompt || ''))) return null;
    return {
      _id: 'prod-c#' + topicId + '#' + idx,
      _topicId: topicId,
      type: 'type',
      tag: ex.tag,
      prompt: ex.prompt,
      answer: ex.answer,
    };
  }
  if (ex.type === 'bank') {
    return {
      _id: 'prod-b#' + topicId + '#' + idx,
      _topicId: topicId,
      type: 'type',
      tag: ex.tag,
      prompt: ex.prompt + ' (type the full sentence)',
      answer: ex.answer,
    };
  }
  if (ex.type === 'explain') {
    // typed: given the meaning, recall the idiom
    return {
      _id: 'prod-e#' + topicId + '#' + idx,
      _topicId: topicId,
      type: 'gaptype',
      tag: ex.tag,
      prompt: 'Type the idiom that means: "' + ex.answer + '".',
      sentence: 'The idiom is: ___.',
      answer: ex.idiom,
    };
  }
  if (ex.type === 'simile') {
    // typed: same template with a typed blank
    return {
      _id: 'prod-s#' + topicId + '#' + idx,
      _topicId: topicId,
      type: 'gaptype',
      tag: ex.tag,
      prompt: 'Type the missing word in the simile' + (ex.meaning ? ' (means: ' + ex.meaning + ')' : '') + '.',
      sentence: ex.template,
      answer: ex.answer,
    };
  }
  return null;
}

window.generateReverseExercises = generateReverseExercises;
window.toProductionVariant = toProductionVariant;
